# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests

# RabbitMQ Management API endpoint
api_endpoint = "http://localhost:15672/api/"

# List of applications and their corresponding virtual hosts
applications = {
    "app1": "vhost1",
    "app2": "vhost2",
    "app3": "vhost3",
}

# Create virtual hosts
for app, vhost in applications.items():
    url = f"{api_endpoint}vhosts/{vhost}"
    payload = {"name": vhost}
    response = requests.put(url, json=payload)

# Create users and set permissions
users = {
    "user1": "password1",
    "user2": "password2",
    "user3": "password3",
}

for user, password in users.items():
    # Create user
    url = f"{api_endpoint}users/{user}"
    payload = {"username": user, "password": password}
    response = requests.put(url, json=payload)

    # Grant permissions for each application
    for app, vhost in applications.items():
        url = f"{api_endpoint}permissions/{user}/{vhost}"
        payload = {
            "configure": ".*",
            "read": ".*",
            "write": ".*",
        }
        response = requests.put(url, json=payload)

print("RabbitMQ virtual hosts and permissions configured successfully.")